INSERT INTO questions(level_id,question_text,option_a,option_b,option_c,option_d,correct_options,question_type,timer_seconds,explanation,source) VALUES
('46c96b65-295a-4683-aa2c-acc9181b42e1','What does AWS stand for?','Advanced Web Services','Amazon Web Services','American Web Systems','Application Web Security','["B"]'::jsonb,'easy',15,'AWS is the cloud computing platform provided by Amazon.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is an ''Availability Zone'' (AZ)?','A single data center','One or more discrete data centers with redundant power, networking, and connectivity in an AWS Region','A collection of regions','A backup server','["B"]'::jsonb,'easy',20,'AZs are designed to provide high availability and fault tolerance within a Region.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service provides resizable virtual servers in the cloud?','S3','EC2','RDS','Lambda','["B"]'::jsonb,'easy',15,'Elastic Compute Cloud (EC2) is the fundamental core of AWS compute.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is the primary storage type of Amazon S3?','Block Storage','Object Storage','File Storage','Archive Storage','["B"]'::jsonb,'easy',15,'S3 stores data as objects within buckets.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is ''IAM'' used for in AWS?','Indexing and Memory','Identity and Access Management: managing users and their access to AWS resources','Internal Application Monitoring','none of the above','["B"]'::jsonb,'easy',20,'IAM allows you to securely control access to AWS services and resources for your users.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is a ''VPC''?','Virtual Private Center','Virtual Private Cloud: a private network in AWS dedicated to your account','Variable Power Consumption','none of the above','["B"]'::jsonb,'easy',20,'A VPC gives you full control over your virtual networking environment.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service is a managed relational database service?','DynamoDB','RDS','ElastiCache','Redshift','["B"]'::jsonb,'easy',15,'RDS (Relational Database Service) supports engines like MySQL, PostgreSQL, and SQL Server.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is the primary benefit of Amazon Lambda?','It''s always running','Serverless compute that runs code in response to events without managing servers','It provides storage','It manages databases','["B"]'::jsonb,'easy',20,'Lambda is a serverless FaaS (Function as a Service) offering.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service is a Content Delivery Network (CDN)?','Route 53','CloudFront','Direct Connect','API Gateway','["B"]'::jsonb,'easy',15,'CloudFront speeds up distribution of static and dynamic web content.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is Amazon Route 53?','A highway navigation tool','A highly available and scalable Domain Name System (DNS) web service','A database service','A ways to name servers','["B"]'::jsonb,'easy',15,'Route 53 translates domain names into IP addresses.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which S3 storage class is best for low-cost, long-term archiving where data is rarely accessed?','S3 Standard','S3 Glacier','S3 Intelligent-Tiering','S3 One Zone-IA','["B"]'::jsonb,'easy',20,'Glacier is designed for data archiving with retrieval times ranging from minutes to hours.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS tool helps you estimate the cost of moving to the cloud?','Cost Explorer','AWS Pricing Calculator','Trusted Advisor','Budgets','["B"]'::jsonb,'easy',15,'The Pricing Calculator lets you estimate costs for your unique use cases.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is the ''Shared Responsibility Model'' in AWS?','AWS handles everything','AWS is responsible for security OF the cloud; the customer is responsible for security IN the cloud','Customers handle everything','Shared responsibility for software development','["B"]'::jsonb,'easy',20,'This model defines the boundary between the service provider and the user.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service is a serverless, key-value NoSQL database service?','RDS','DynamoDB','Aurora','Neptune','["B"]'::jsonb,'easy',20,'DynamoDB offers consistent, single-digit millisecond latency at any scale.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service is used for monitoring and observability of metrics and logs?','CloudTrail','CloudWatch','Config','X-Ray','["B"]'::jsonb,'easy',15,'CloudWatch provides data and actionable insights for AWS resources.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service records API calls for your account for auditing purposes?','CloudWatch','CloudTrail','Inspector','GuardDuty','["B"]'::jsonb,'easy',15,'CloudTrail provides a history of AWS API calls for security and compliance.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What does ''AWS Trusted Advisor'' do?','It manages your servers','It provides recommendations in categories like cost optimization, performance, and security','It''s a person you can call','It writes your code','["B"]'::jsonb,'easy',20,'Trusted Advisor checks your environment against AWS best practices.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service allows you to run Docker containers on AWS without managing servers?','EC2','Fargate','S3','VPC','["B"]'::jsonb,'easy',15,'AWS Fargate is a serverless compute engine for containers that works with both ECS and EKS.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is the name of the Amazon web-scale container orchestration service?','ECS','EKS','EC2','S3','["A"]'::jsonb,'easy',15,'Elastic Container Service (ECS) is a highly scalable, high-performance container management service.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is the Amazon service for running Kubernetes in the cloud?','ECS','EKS','EB','Lambda','["B"]'::jsonb,'easy',15,'Elastic Kubernetes Service (EKS) makes it easy to deploy, manage, and scale containerized applications using Kubernetes.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is ''EBS'' stand for?','Elastic Block Store','External Backup System','Extended Building Service','none of the above','["A"]'::jsonb,'easy',15,'EBS provides persistent block storage volumes for use with EC2 instances.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service automatically distributes incoming application traffic across multiple targets, such as EC2 instances?','Route 53','Elastic Load Balancing (ELB)','Auto Scaling','CloudFront','["B"]'::jsonb,'easy',20,'ELB scaling ensures high availability by distributing traffic.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is an AWS ''Region''?','A single data center','A physical location in the world where AWS has multiple Availability Zones','A ways to name servers','A collection of countries','["B"]'::jsonb,'easy',15,'Regions are geographically isolated areas where AWS resources reside.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is the purpose of ''AWS Auto Scaling''?','To delete old servers','To automatically add or remove resources to meet demand','To rename servers','To backup data','["B"]'::jsonb,'easy',15,'Auto Scaling helps maintain application availability and allows you to scale up or down automatically.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which pricing model allows you to pay less by committing to a consistent amount of usage (e.g. 1 or 3 years)?','On-Demand','Reserved Instances / Savings Plans','Spot Instances','none of the above','["B"]'::jsonb,'easy',20,'Reserved Instances and Savings Plans provide significant discounts compared to On-Demand pricing.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service provides protection against DDoS attacks?','AWS Shield','AWS WAF','Inspector','KMS','["A"]'::jsonb,'easy',15,'AWS Shield is a managed Distributed Denial of Service (DDoS) protection service.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service is a web application firewall that helps protect your web applications from common web exploits?','AWS WAF','Shield','IAM','Certificate Manager','["A"]'::jsonb,'easy',15,'AWS WAF gives you control over which traffic to allow or block to your web applications.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service is a petabyte-scale data transport solution that uses physical devices?','Direct Connect','AWS Snowball','Transfer Family','Storage Gateway','["B"]'::jsonb,'easy',20,'Snowball is used for large-scale data transfers into or out of AWS.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is the main advantage of ''Serverless'' computing?','There are no servers','Developers can focus on code without worrying about server provisioning, management, or scaling','It''s always free','It''s faster than EC2','["B"]'::jsonb,'easy',20,'Serverless (like Lambda) abstracts away the underlying infrastructure management.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is ''Amazon EFS''?','Elastic File System: a simple, scalable, serverless, set-and-forget file system','Extra Fast Storage','Easy Folder Service','none of the above','["A"]'::jsonb,'easy',15,'EFS provides a managed file system that can be accessed by multiple EC2 instances simultaneously.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service is a fully managed in-memory data store?','Redshift','ElastiCache','RDS','Neptune','["B"]'::jsonb,'easy',15,'ElastiCache improves application performance by retrieving data from fast in-memory caches.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service is a fast, fully managed data warehouse that makes it simple and cost-effective to analyze all your data?','Athena','Redshift','Glue','Kinesis','["B"]'::jsonb,'easy',20,'Redshift uses SQL to analyze large amounts of data across your data warehouse and data lake.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which interactive query service makes it easy to analyze data in Amazon S3 using standard SQL?','Redshift','Athena','EMR','QuickSight','["B"]'::jsonb,'easy',20,'Athena is serverless, so there is no infrastructure to manage, and you pay only for the queries that you run.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service is a fully managed message queuing service (MQS)?','SNS','SQS','SES','SWF','["B"]'::jsonb,'easy',15,'Simple Queue Service (SQS) allows you to decouple and scale microservices.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service is a fully managed pub/sub messaging service?','SQS','SNS','SES','Pinpoint','["B"]'::jsonb,'easy',15,'Simple Notification Service (SNS) enables fast, highly scalable messaging.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service provides a fully managed service that enables developers to quickly build, train, and deploy machine learning models?','Rekognition','SageMaker','Lex','Polly','["B"]'::jsonb,'easy',20,'SageMaker takes away the heavy lifting of machine learning.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is the purpose of ''AWS Secrets Manager''?','To hide your files','To rotatable, manage, and retrieve database credentials, API keys, and other secrets throughout their lifecycle','To encrypt your code','none of the above','["B"]'::jsonb,'easy',20,'Secrets Manager helps you replace hardcoded credentials in your code with an API call.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service is a managed service that makes it easy for you to create and control the master keys used to encrypt your data?','IAM','AWS KMS (Key Management Service)','CloudHSM','Secrets Manager','["B"]'::jsonb,'easy',20,'KMS integrates with most other AWS services to help you protect your data.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is ''AWS Organizations'' used for?','To name your departments','To centrally manage and govern your environment as you grow and scale your AWS resources','To backup your account','none of the above','["B"]'::jsonb,'easy',15,'Organizations helps with billing, security, and compliance across multiple AWS accounts.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service provides an easy way to create and manage a collection of related AWS resources, provisioning and updating them in an orderly fashion?','Beanstalk','CloudFormation','OpsWorks','CodeDeploy','["B"]'::jsonb,'easy',20,'CloudFormation is the primary IaC (Infrastructure as Code) tool on AWS.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is ''AWS Elastic Beanstalk''?','A ways to grow plants','An easy-to-use service for deploying and scaling web applications and services developed with Java, .NET, PHP, Node.js, Python, Ruby, Go, and Docker','A ways to store data','none of the above','["B"]'::jsonb,'easy',20,'Beanstalk is a PaaS (Platform as a Service) that automates deployment tasks.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service enables you to assess, audit, and evaluate the configurations of your AWS resources?','AWS Config','CloudTrail','CloudWatch','Inspector','["A"]'::jsonb,'easy',15,'Config provides a detailed view of the configuration of AWS resources in your account.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service is an automated security assessment service that helps improve the security and compliance of applications deployed on AWS?','GuardDuty','Amazon Inspector','Shield','Macie','["B"]'::jsonb,'easy',20,'Inspector automatically assesses applications for exposure, vulnerabilities, and deviations from best practices.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service is a threat detection service that continuously monitors for malicious activity and unauthorized behavior?','Inspector','Amazon GuardDuty','WAF','Shield','["B"]'::jsonb,'easy',20,'GuardDuty uses machine learning, anomaly detection, and integrated threat intelligence to identify and prioritize potential threats.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which service uses machine learning and pattern matching to discover and protect your sensitive data in AWS?','GuardDuty','Amazon Macie','Inspector','KMS','["B"]'::jsonb,'easy',20,'Macie helps you maintain security and compliance by discovering and protecting sensitive PII data.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is ''AWS Artifact''?','A ways to name files','A central resource for compliance-related information that provides on-demand access to AWS’ security and compliance reports','A backup service','none of the above','["B"]'::jsonb,'easy',15,'Artifact helps you demonstrate compliance to auditors or regulators.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is ''AWS Outposts''?','A ways to name servers','A fully managed service that offers the same AWS infrastructure, AWS services, APIs, and tools to virtually any data center, co-location space, or on-premises facility','A backup server','none of the above','["B"]'::jsonb,'easy',15,'Outposts provides a truly consistent hybrid experience.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','What is ''AWS CodeCommit''?','A fully managed source control service that hosts secure Git-based repositories','A ways to name code','A tool to delete branches','none of the above','["A"]'::jsonb,'easy',15,'CodeCommit makes it easy for teams to collaborate on code.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS service helps you migrate databases to AWS quickly and securely?','SMS','Database Migration Service (DMS)','Snowball','S3','["B"]'::jsonb,'easy',20,'DMS can migrate your data to and from most widely used commercial and open-source databases.','pregenerated'),
('46c96b65-295a-4683-aa2c-acc9181b42e1','Which AWS tool gives you the ability to set custom budgets that alert you when your costs or usage exceed (or are forecasted to exceed) your budgeted amount?','Cost Explorer','AWS Budgets','Pricing Calculator','none of the above','["B"]'::jsonb,'easy',15,'Budgets help you stay informed about your AWS spending.','pregenerated')
INSERT INTO questions(level_id,question_text,option_a,option_b,option_c,option_d,correct_options,question_type,timer_seconds,explanation,source) VALUES
('056f4b6f-2549-44c1-ad01-4313343b97e8','What are the four main elements of an IAM Policy statement?','ID, User, Group, Role','Effect, Action, Resource, Condition','Name, Date, Size, Type','Principal, Target, Method, Logic','["B"]'::jsonb,'medium',25,'These elements define ''who'' can do ''what'' on ''which'' resource under ''what'' conditions.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','Which EC2 instance family is best suited for compute-intensive applications like batch processing or high-performance web servers?','T (General Purpose)','C (Compute Optimized)','R (Memory Optimized)','I (Storage Optimized)','["B"]'::jsonb,'medium',30,'C-series instances are designed for applications that benefit from high-performance processors.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is the difference between General Purpose SSD (gp2/gp3) and Provisioned IOPS SSD (io1/io2)?','One is faster','Provisioned IOPS is for mission-critical applications that require sustained IOPS performance beyond what General Purpose can provide','gp2 is only for small files','none of the above','["B"]'::jsonb,'medium',25,'IOPS-intensive workloads like large databases need provisioned IOPS for reliability.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''S3 Lifecycle Management'' used for?','To delete old versions of files','To automatically transition objects between different storage classes (e.g. from Standard to Glacier) based on age to optimize costs','To rename buckets','To encrypt files','["B"]'::jsonb,'medium',30,'Lifecycle rules automate cost-saving transitions as data ages.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is the primary difference between a ''Security Group'' and a ''Network ACL'' (NACL)?','One is for users, one is for groups','Security Groups are stateful (returning traffic is allowed) and at the instance level; NACLs are stateless and at the subnet level','NACLs are faster','none of the above','["B"]'::jsonb,'medium',30,'Security groups provide fine-grained control for specific instances, while NACLs provide a broader security layer for the entire subnet.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','In Amazon RDS, what is the purpose of ''Multi-AZ'' deployment?','To provide high availability and automatic failover by maintaining a synchronous standby instance in a different AZ','To increase read performance','To decrease costs','To move the database to a new region','["A"]'::jsonb,'medium',30,'Multi-AZ is for fault tolerance; Read Replicas are for performance scaling.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','When would you use an Amazon RDS ''Read Replica''?','To provide high availability','To offload read-intensive workloads from the primary database instance and improve scaling','To backup the database','none of the above','["B"]'::jsonb,'medium',25,'Read replicas allow you to scale out read performance by distributing traffic among multiple copies.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''Latency-based'' routing in Route 53?','Routing to the closest geographic region','Routing traffic to the AWS region that provides the lowest latency for the end user','Routing to a server with the most RAM','none of the above','["B"]'::jsonb,'medium',30,'Latency routing improves user experience by selecting the fastest responding endpoint.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is an ''Origin Access Identity'' (OAI) in CloudFront?','A ways to name a user','A special CloudFront user that allows you to restrict access to an S3 bucket content so it can only be accessed via CloudFront and not directly','An encryption key','none of the above','["B"]'::jsonb,'medium',25,'OAI enhances security by forcing traffic through your CDN, where you can enforce WAF rules or signed URLs.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is a ''Target Tracking Scaling Policy''?','Adding a fixed number of instances','A policy that adjusts the number of instances to maintain a specific metric (e.g. average CPU utilization at 50%)','Scaling based on the time of day','none of the above','["B"]'::jsonb,'medium',30,'Target tracking is the easiest and most responsive way to manage auto-scaling based on load.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is the purpose of a ''NAT Gateway''?','To allow public subnet instances to access the internet','To allow private subnet instances to access the internet (e.g. for updates) while preventing the internet from initiating a connection to those instances','To translate IPv6 to IPv4','none of the above','["B"]'::jsonb,'medium',25,'NAT Gateways are essential for maintaining the security of private workloads while still allowing them outbound access.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','Which IAM entity should be used for granting temporary permissions to an AWS service (like EC2) to access other services (like S3)?','IAM User','IAM Group','IAM Role','Access Key','["C"]'::jsonb,'medium',25,'Roles eliminate the need for hardcoded credentials on instances by providing temporary tokens.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''DynamoDB DAX''?','A backup tool','A fully managed, highly available, in-memory cache for DynamoDB that delivers up to 10x performance improvement','A ways to name tables','none of the above','["B"]'::jsonb,'medium',30,'DAX (DynamoDB Accelerator) provides microsecond latency for read-intensive data.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What does S3 ''Versioning'' provide?','Encryption for files','The ability to keep multiple variants of an object in the same bucket, allowing for recovery from accidental deletion or overwrite','A ways to name files','Lower storage costs','["B"]'::jsonb,'medium',30,'Versioning is a critical feature for data protection and compliance.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','Inside a CloudFormation template, what is the ''Parameters'' section used for?','To define the resources','To enable you to input custom values to your template each time you create or update a stack','To output the results','To define the license','["B"]'::jsonb,'medium',25,'Parameters make templates reusable across different environments and configurations.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','How can you restrict access to one specific object in an S3 bucket?','Bucket Policy only','Object ACL (Access Control List)','Naming the file differently','Changing the bucket name','["B"]'::jsonb,'medium',25,'ACLs can be used at the object level for individual permission management, though bucket policies are generally preferred for bulk management.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is the ''Cold Start'' problem in Lambda?','The server room is literally cold','The latency experienced when a function is triggered after being idle, as AWS must spin up a new execution environment','The code won''t compile','none of the above','["B"]'::jsonb,'medium',30,'Cold starts can impact user-facing application performance for infrequently called functions.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','Which of these are characteristics of Amazon SQS?','Standard queues provide ''at-least-once'' delivery','FIFO queues provide ''exactly-once'' processing','It is synchronous','It is highly scalable','["A","B","D"]'::jsonb,'multi_correct',35,'SQS is an asynchronous messaging service with scalable standard and specialized FIFO options.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is a Route 53 ''Alias'' record?','A ways to name a user','An AWS-specific routing record that points to internal AWS resources (like ELB, S3 websites) without incurring additional DNS query costs','A nickname for a server','A CNAME record','["B"]'::jsonb,'medium',25,'Alias records are more efficient and flexible than standard CNAME records for AWS-integrated DNS.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','How does Amazon Aurora differ from standard RDS MySQL?','It''s free','It is cloud-native, uses a purpose-built distributed storage system, and can scale up to 15 read replicas with very low lag','It is slower','It doesn''t support SQL','["B"]'::jsonb,'medium',30,'Aurora is AWS''s proprietary relational engine built for performance and scale in the cloud.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''AWS Key Management Service'' (KMS) Customer Master Key (CMK)?','A key given to every user','The logical representation of a master key which includes the metadata and the key material used to encrypt/decrypt data-encryption keys','A ways to name a project','none of the above','["B"]'::jsonb,'medium',25,'CMKs are the foundational component for data encryption on AWS.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is an ''SCP'' (Service Control Policy) in AWS Organizations?','A ways to name a user','A policy that defines the maximum permissions available for members of an organization, allowing for central governance and prevention of unauthorized service use','A ways to backup data','none of the above','["B"]'::jsonb,'medium',30,'SCPs allow administrators to restrict whole accounts from using specific sensitive services (like preventing any use of RDS).','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''VPC Peering''?','A ways to see other VPCs','A networking connection between two VPCs that enables you to route traffic between them using private IPv4 or IPv6 addresses','A ways to delete a VPC','none of the above','["B"]'::jsonb,'medium',25,'Peering allows private communication between resources in different VPCs within the same or different AWS accounts.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What handles ''S3 Transfer Acceleration''?','Buying faster internet','AWS Edge Locations around the world which route your data through an optimized network path to the S3 bucket','Deleting old files','none of the above','["B"]'::jsonb,'medium',25,'Transfer acceleration significantly speeds up long-distance uploads by using the AWS global backbone.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is an ''AWS Config Rule''?','A ways to name a user','A rule that continuously monitors your resource configurations for compliance with your desired settings and best practices','A laws for using AWS','none of the above','["B"]'::jsonb,'medium',30,'Config Rules allow for automated auditing and remediation of non-compliant resource states.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is the purpose of ''AWS CodeBuild''?','To write code','A fully managed continuous integration service that compiles source code, runs tests, and produces software packages that are ready to deploy','To rename files','none of the above','["B"]'::jsonb,'medium',25,'CodeBuild is the ''build'' stage of the AWS developer toolset, allowing for pay-as-you-go compilation.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What characterizes ''Blue/Green Deployment'' in AWS?','Two versions of the logo','A strategy where you maintain two identical production environments and use routing to switch traffic from one (Blue) to the other (Green) for a risk-free release','Updating the OS','none of the above','["B"]'::jsonb,'medium',30,'Blue/green deployments are easily implemented using Route 53 or ELB weighting.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''Amazon FSx for Windows File Server''?','A ways to host websites','A fully managed, highly reliable, and scalable file storage that is accessible over the industry-standard Service Message Block (SMB) protocol','A backup tool for Windows','none of the above','["B"]'::jsonb,'medium',25,'FSx is designed specifically for workloads that require native Windows file compatibility and features.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is a ''CloudWatch Dashboard''?','A ways to name a user','A customizable home page for your metrics that allows you to see graph-based data for various resources in a single view','A tool to delete logs','none of the above','["B"]'::jsonb,'medium',30,'Dashboards provide a central visualization hub for system health and performance.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','In the ''Well-Architected Framework'', what is the ''Operational Excellence'' pillar focused on?','Making the most money','The ability to run and monitor systems to deliver business value and to continually improve supporting processes and procedures','Designing faster chips','none of the above','["B"]'::jsonb,'medium',30,'Operational Excellence includes automation, testing, and responding to events.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is the primary goal of the ''Cost Optimization'' pillar of the Well-Architected Framework?','To hire fewer people','To deliver systems that achieve business outcomes at the lowest price point','To delete old code','To avoid paying for AWS','["B"]'::jsonb,'medium',25,'Cost optimization is about right-sizing and leveraging lower-cost architectures.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is the difference between S3 ''Standard'' and S3 ''Standard-IA''?','Standard is faster','Standard-IA (Infrequent Access) has a lower storage cost but charges a fee for data retrieval','one is for small files','none of the above','["B"]'::jsonb,'medium',25,'IA is designed for data that is needed immediately but accessed less frequently (e.g. monthly backups).','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What defines ''DynamoDB Provisioned Throughput''?','The size of the table','The amount of read and write units (RCU/WCU) you specify for the table, which governs its performance limit','The number of users','none of the above','["B"]'::jsonb,'medium',30,'Provisioning ensures your table can handle the expected traffic, though on-demand mode is also available.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is an AWS ''Savings Plan''?','A ways to hide money','A flexible pricing model that offers low prices on EC2, Lambda, and Fargate in exchange for a commitment to a consistent amount of usage (e.g. $10/hour)','A ways to name a user','none of the above','["B"]'::jsonb,'medium',25,'Savings plans are more flexible than traditional Reserved Instances, covering multiple compute services.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''AWS Application Migration Service'' (MGN)?','A tool to move photos','The primary service for lift-and-shift migrations to AWS, using block-level data replication from source to target','A ways to delete apps','none of the above','["B"]'::jsonb,'medium',25,'MGN automates the migration of on-premises servers to EC2.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is an AWS ''Edge Location''?','A ways to name a region','A global network of data centers (different from Regions/AZs) used by services like CloudFront and Route 53 to deliver content with lower latency','A data center at the edge of town','none of the above','["B"]'::jsonb,'medium',25,'Edge locations are the points-of-presence for Content Delivery Networks.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','Which AWS service helps you centrally manage credentials for your AWS resources and applications?','KMS','AWS Secrets Manager','Inspector','CloudTrail','["B"]'::jsonb,'medium',30,'Secrets Manager is specialized for secrets that change frequently or need rotation, like DB passwords.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is a ''Customer Gateway'' in a Site-to-Site VPN?','An AWS router','The technical representation of the on-premises VPN device in your AWS network configuration','A ways to name a user','none of the above','["B"]'::jsonb,'medium',25,'A Customer Gateway provides the endpoint information for the AWS side of the VPN tunnel.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''AWS Transit Gateway''?','A hub that connects VPCs and on-premises networks through a central point','A ways to name a router','A backup service','none of the above','["A"]'::jsonb,'medium',25,'Transit Gateway simplifies networking by removing the need for complex VPC peering meshes at scale.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''Redshift Spectrum''?','A ways to name colors','A feature that allows you to run SQL queries against data stored directly in S3 without first loading it into Redshift tables','A tool to delete data','none of the above','["B"]'::jsonb,'medium',30,'Spectrum bridges the gap between structured data warehouses and unstructured data lakes.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','How is Lambda pricing calculated?','By the number of lines of code','Based on the number of requests and the duration (amount of time the code runs for) combined with the memory allocated to the function','By the month','none of the above','["B"]'::jsonb,'medium',25,'Lambda''s pay-per-execution model makes it extremely cost-effective for bursty workloads.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What characterizes ''Amazon GuardDuty'' findings?','They are always false','They provide information about the severity, the resources involved, and the type of potential security issue detected using machine learning','They are only for S3','none of the above','["B"]'::jsonb,'medium',30,'GuardDuty results are ranked from ''Low'' to ''High'' to help security teams prioritize response.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''AWS CodePipeline''?','A ways to name some code','A fully managed continuous delivery service that helps you automate your release pipelines for fast and reliable application and infrastructure updates','A tool to delete old builds','none of the above','["B"]'::jsonb,'medium',25,'CodePipeline orchestrates the flow from source to build to deploy.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''AWS App Runner''?','A software for running marathons','A fully managed service that makes it easy for developers to quickly deploy containerized web applications and APIs, at scale and with no prior infrastructure experience required','A ways to name containers','none of the above','["B"]'::jsonb,'medium',25,'App Runner is an even higher-level serverless abstraction than Fargate for web apps.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','Which S3 feature allows you to replicate data across different AWS regions for disaster recovery?','Same-Region Replication (SRR)','Cross-Region Replication (CRR)','Object Lock','Versioning','["B"]'::jsonb,'medium',30,'CRR helps meet compliance requirements and minimizes latency for users in different continents.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What describes ''AWS Control Tower''?','A tower in the data center','A service that makes it easy to set up and govern a secure, multi-account AWS environment based on best practices (Landing Zones)','A ways to name a user','none of the above','["B"]'::jsonb,'medium',25,'Control Tower automates the creation of a ''Landing Zone'' environment for large organizations.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is the benefit of ''S3 Object Lock''?','It hides the file from others','It prevents objects from being deleted or overwritten for a fixed amount of time or indefinitely (WORM model)','A ways to name a file','none of the above','["B"]'::jsonb,'medium',25,'Object Lock is essential for regulatory compliance (e.g. SEC Rule 17a-4) that requires data immutability.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''AWS CDK''?','A data kit','Cloud Development Kit: an open-source software development framework to define cloud infrastructure in code (e.g. TypeScript, Python) and provision it through CloudFormation','A ways to name a stack','none of the above','["B"]'::jsonb,'medium',25,'CDK allows developers to use familiar programming languages instead of YAML/JSON for IaC.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is an ''AMI'' (Amazon Machine Image)?','A ways to name servers','A template that contains the software configuration (operating system, application server, and applications) required to launch an EC2 instance','An encryption key','none of the above','["B"]'::jsonb,'medium',25,'AMIs are the ''blueprints'' for creating repeatable virtual machines.','pregenerated'),
('056f4b6f-2549-44c1-ad01-4313343b97e8','What is ''Amazon Neptune''?','A planetary database','A fast, reliable, fully managed graph database service that makes it easy to build and run applications that work with highly connected datasets','A backup tool','none of the above','["B"]'::jsonb,'medium',25,'Neptune is optimized for graph use cases like social networks or fraud detection.','pregenerated')
INSERT INTO questions(level_id,question_text,option_a,option_b,option_c,option_d,correct_options,question_type,timer_seconds,explanation,source) VALUES
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''AWS PrivateLink'' used for?','To connect two VPCs via peering','To provide private connectivity between VPCs, AWS services, and your on-premises networks without exposing traffic to the public internet','To speed up the internet','none of the above','["B"]'::jsonb,'hard',45,'PrivateLink uses interface endpoints to securely connect services while keeping traffic on the AWS backbone.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','How does ''AWS Direct Connect'' (DX) differ from a Standard Site-to-Site VPN?','DX is free','DX provides a dedicated, private physical network connection from your premises to AWS, offering more consistent performance and lower latency than an internet-based VPN','VPN is faster','none of the above','["B"]'::jsonb,'hard',40,'Direct Connect is ideal for large datasets or high-bandwidth requirements that need guaranteed throughput.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''Policy Evaluation Logic'' in AWS IAM when multiple policies are attached to a user?','The longest policy wins','By default, all requests are denied. Any explicit ''Deny'' always overrides any ''Allow''. An ''Allow'' is only granted if there is no explicit ''Deny'' and there is an explicit ''Allow''','The last policy added wins','Developers always have access','["B"]'::jsonb,'hard',50,'Implicit Deny -> Explicit Allow -> Explicit Deny (Deny wins!). Understanding this hierarchy is vital for complex permission troubleshooting.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is the primary difference between a ''Global Secondary Index'' (GSI) and a ''Local Secondary Index'' (LSI)?','GSI is for global users','GSIs can have a partition key and sort key that are different from the base table; LSIs must have the same partition key as the table but a different sort key','LSI is faster','GSIs cannot be created after the table is created','["B"]'::jsonb,'hard',45,'GSIs are much more flexible and can span the entire table; LSIs are tied to the partition of the base table''s partition key.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''DynamoDB Global Tables''?','Tables that everyone can see','A fully managed, multi-region, multi-active database that automatically replicates your DynamoDB tables across your choice of AWS Regions','A ways to name a table','none of the above','["B"]'::jsonb,'hard',45,'Global Tables provide low-latency reads and writes to locally available users in different regions.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','When would you prefer ''Lambda@Edge'' over ''CloudFront Functions''?','For simple header changes','For complex or long-running tasks that require external network calls or large libraries (like image manipulation)','CloudFront Functions is always better','none of the above','["B"]'::jsonb,'hard',40,'CloudFront Functions is optimized for sub-millisecond, low-compute tasks; Lambda@Edge is more powerful but slower and more expensive.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''VPC Flow Logs'' and what can it tell you?','A logs of the weather','A feature that enables you to capture information about the IP traffic (Accepted or Rejected) going to and from network interfaces in your VPC','A list of users who logged in','none of the above','["B"]'::jsonb,'hard',45,'Flow logs are critical for security auditing and debugging why specific traffic is being blocked by Security Groups or NACLs.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''CloudFormation StackSets''?','A ways to name a stack','A feature that allows you to create, update, or delete stacks across multiple AWS accounts and regions with a single operation','A tool to delete old stacks','none of the above','["B"]'::jsonb,'hard',50,'StackSets are essential for enterprise-scale infrastructure management across many accounts.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''CloudWatch Logs Insights''?','A ways to see the logs','A powerful, interactive log analytics service that allows you to query your CloudWatch logs using a specialized purpose-built query language','A ways to delete old logs','none of the above','["B"]'::jsonb,'hard',45,'Insights allows you to aggregate, filter, and analyze log data at scale without needing an ELK stack.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''AWS Systems Manager Parameter Store'' compared to ''Secrets Manager''?','They are the same','Parameter Store is more cost-effective for general configuration; Secrets Manager is designed for sensitive data with built-in rotation and higher cost','Secrets Manager is for large files','none of the above','["B"]'::jsonb,'hard',45,'Parameter Store is great for strings and lists; Secrets Manager is better for relational DB keys that change.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What characterizes ''API Gateway Usage Plans''?','Plans for developers','The ability to define different tiers for API consumers, including rate limiting (throttling) and quota management (e.g. 1000 requests per month)','A ways to name the API','none of the above','["B"]'::jsonb,'hard',50,'Usage plans allow you to monetize or control access to your APIs for different client segments.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''Lambda Provisioned Concurrency''?','A ways to run many functions','A feature that keeps a specified number of execution environments warm and ready to respond immediately to function calls, eliminating ''cold starts''','A ways to delete old functions','none of the above','["B"]'::jsonb,'hard',45,'Provisioned concurrency is for high-performance applications that cannot tolerate the 1-2 second lag of a container cold start.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is the ''S3 bucket policy'' condition `aws:SecureTransport` used for?','To encrypt the data on disk','To enforce that all connections to the S3 bucket must use HTTPS (SSL/TLS)','To name the bucket securely','none of the above','["B"]'::jsonb,'hard',45,'This condition is a common security best practice to prevent data-in-transit from being intercepted.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What defines ''Amazon Aurora Serverless v2''?','It''s always running','An on-demand, auto-scaling configuration for Aurora that scales capacity in fine-grained increments (ACUs) to meet the needs of the most demanding applications','It is slower than v1','none of the above','["B"]'::jsonb,'hard',50,'v2 is faster at scaling and more efficient at handling low-load states than the original Aurora Serverless.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is a ''VPC Endpoint'' in AWS?','A ways to delete a VPC','A private connection between your VPC and supported AWS services without requiring an internet gateway, NAT device, or VPN connection','A ways to name a user','A physical router','["B"]'::jsonb,'hard',45,'Endpoints (Interface or Gateway) improve security and reduce costs by keeping traffic inside the AWS network.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is an ''Identity Provider'' (IdP) in IAM?','A ways to name a user','An external entity (like Google, OKTA, or Active Directory) that provides identities for your AWS account using standard protocols like SAML 2.0 or OIDC','A backup account','none of the above','["B"]'::jsonb,'hard',45,'Federation through an IdP allows for Single Sign-On (SSO) across enterprise applications and AWS.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is the role of an ''AWS Global Accelerator''?','To speed up the internet globally','A service that uses the AWS global network backbone to improve the availability and performance of your applications for local and global users by providing two static anycast IP addresses','To rename regions','none of the above','["B"]'::jsonb,'hard',50,'Global Accelerator optimizes the network path and automatically fails over between regions without DNS propagation delays.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What happens if a DynamoDB table with Provisioned capacity exceeds its RCU or WCU limit?','AWS adds more capacity automatically and charges you','The requests will be ''Throttled'', returning a 400 error to the client','The table is deleted','none of the above','["B"]'::jsonb,'hard',40,'Throttling requires applications to implement retries with exponential backoff.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''Amazon EFS Access Points''?','A physical connection to EFS','Application-specific entry points into an EFS file system that make it easy to manage application access to shared datasets','A ways to name folders','none of the above','["B"]'::jsonb,'hard',45,'Access points can enforce specific user IDs and paths, making EFS easier to use in multi-tenant container environments.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is the purpose of ''AWS Migration Hub''?','A place to see your migrations','A central location to find migration tools and track the progress of migrations across multiple AWS and partner solutions','A ways to name a user','none of the above','["B"]'::jsonb,'hard',40,'Migration Hub provides a single dashboard to manage the complex journey of moving data and apps to AWS.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What characterizes an ''AWS KMS Multi-Region Key''?','A key that everyone can use','A set of identical KMS keys that can be replicated across different regions, allowing for seamless encryption/decryption of the same data in those regions','A ways to name the keys','none of the above','["B"]'::jsonb,'hard',45,'Multi-region keys simplify global data management and disaster recovery architectures.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''AWS Lambda Layers''?','A ways to wrap the code','A distribution mechanism for libraries, custom runtimes, and other function dependencies that can be shared across multiple Lambda functions','A tool to delete old code','none of the above','["B"]'::jsonb,'hard',45,'Layers reduce deployment package size and promote code reuse.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''SQS Visibility Timeout''?','The time the queue is hidden','The period of time during which SQS prevents other consumers from receiving and processing a message that has already been picked up by one consumer','The time before a message is deleted','none of the above','["B"]'::jsonb,'hard',40,'If the consumer doesn''t delete the message before the timeout expires, the message becomes visible again for other consumers.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''AWS Step Functions''?','A ways to name a user','A serverless orchestration service that lets you combine AWS Lambda functions and other AWS services to build business-critical applications','A ways to count lines of code','none of the above','["B"]'::jsonb,'hard',45,'Step Functions state machines help you manage complex workflows and retry logic.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''AWS Glue''?','A liquid for building servers','A fully managed ETL (extract, transform, and load) service that makes it easy for customers to prepare and load their data for analytics','A ways to name a user','none of the above','["B"]'::jsonb,'hard',45,'Glue includes a data catalog and crawlers to discover metadata from your data sources automatically.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is the purpose of ''Amazon Macie'' sensitive data discovery?','To find photos of users','To use machine learning to automatically discover and protect sensitive personal information (PII) like social security numbers or credit card details in S3','To rename files','none of the above','["B"]'::jsonb,'hard',50,'Macie helps prevent data leaks by flagging sensitive data that might be exposed to the public.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is a ''T3 Unlimited'' instance in EC2?','An instance with unlimited RAM','An instance that can burst CPU performance above its baseline as long as needed, incurring additional costs if it exhausts its accrued credits','An instance with no storage limits','none of the above','["B"]'::jsonb,'hard',45,'Unlimited mode allows burstable instances to handle sustained high load without being throttled.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is the difference between RDS ''Snapshot'' and ''Automated Backup''?','Snapshots are only for large databases','Automated backups are enabled by default and deleted when the RDS instance is deleted; Snapshots are user-initiated and persist after the instance is deleted','Snapshots are faster','none of the above','["B"]'::jsonb,'hard',45,'Snapshots are manual points-in-time; Automated backups cover your recovery window (up to 35 days).','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''AWS Resource Groups''?','A group of users','A feature that allows you to organize and manage your AWS resources based on tags (e.g. all resources for App-X in Production)','A tool to delete old resources','none of the above','["B"]'::jsonb,'hard',40,'Resource Groups make it easier to view and manage related infrastructure at scale.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is the primary difference between Redis and Memcached in Amazon ElastiCache?','Memcached is newer','Redis supports complex data types (lists, sets) and replication/high-availability; Memcached is a simple key-value store optimized for simple caching','Redis is only for small files','none of the above','["B"]'::jsonb,'hard',45,'Choose Redis for more advanced features like persistence and pub/sub; choose Memcached for massive-scale, simple string caching.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''Egress-only Internet Gateway''?','A ways to delete the internet','A VPC component that allows IPv6 traffic from your private subnet to the internet, but prevents the internet from initiating a connection to those instances','A ways to name a router','none of the above','["B"]'::jsonb,'hard',45,'This is essentially a NAT Gateway equivalent for IPv6 traffic.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What characterizes ''Amazon Cognito User Pools''?','A swimming pool for users','A user directory that provides sign-up and sign-in options for your app users, managing the entire authentication flow','A ways to name a user','none of the above','["B"]'::jsonb,'hard',50,'Cognito handles user registration, authentication, and password recovery.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is an ''AWS Config Remediation''?','A ways to hide money','The ability of AWS Config to automatically fix (remediate) non-compliant resources using SSM Automation documents','A ways to delete a user','none of the above','["B"]'::jsonb,'hard',45,'Remediation helps you maintain a secure environment without manual intervention.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is a ''Change Set'' in AWS CloudFormation?','A set of new clothes for the server','A summary of the changes that CloudFormation will make to your stack, allowing you to preview them before executing the update','A ways to rename a stack','none of the above','["B"]'::jsonb,'hard',45,'Change sets are a key safety feature to prevent unexpected infrastructure destruction.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What defines ''AWS Cloud Map''?','A physical map of data centers','A cloud resource discovery service that lets you name your application resources with custom names, and it automatically updates the location of these dynamically changing resources','A ways to delete images','none of the above','["B"]'::jsonb,'hard',45,'Cloud Map is a service discovery tool that simplifies managing microservices that scale and move frequently.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''Amazon Kinesis Data Streams''?','A ways to stream movies','A serverless real-time data streaming service that can continuously capture gigabytes of data per second from hundreds of thousands of sources','A tool to delete old data','none of the above','["B"]'::jsonb,'hard',45,'Kinesis is the primary tool for handling massive, high-throughput streaming data for real-time analysis.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What characterizes ''Amazon S3 Glacier Deep Archive''?','A ways to hide files in a cave','The lowest-cost storage class on AWS, designed for long-term retention of data that is accessed at most once or twice a year, with retrieval times of 12-48 hours','A ways to name old files','none of the above','["B"]'::jsonb,'hard',45,'Deep Archive is much cheaper than tape-based offsite storage for compliance data.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''AWS Systems Manager Patch Manager'' used for?','To name the servers','An automated tool that helps you simplify your operating system patching process across large fleets of EC2 instances and on-premises servers','A ways to delete old code','none of the above','["B"]'::jsonb,'hard',45,'Patch Manager uses ''Patch Baselines'' to enforce standard security update levels across your infrastructure.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','Which element in an IAM trust policy defines which principal is allowed to assume a role?','Action','Principal','Resource','Condition','["B"]'::jsonb,'hard',50,'The Principal element specifies the user, account, or service (e.g. lambda.amazonaws.com) that can inherit the role''s permissions.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''AWS Site-to-Site VPN''?','A ways to name a website','A secure, encrypted connection between a VPC and your remote network (e.g. corporate data center) over the public internet','A ways to delete a user','none of the above','["B"]'::jsonb,'hard',45,'VPN is a quick and cost-effective way to establish hybrid connectivity compared to Direct Connect.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''Amazon GuardDuty'' malware scan?','Scanning for sick users','A feature that automatically initiates agentless malware scans of Amazon EBS volumes when GuardDuty detects suspicious activity indicative of malware','A ways to name a file','none of the above','["B"]'::jsonb,'hard',45,'Malware scanning provides deep visibility into compromised instances without affecting their performance.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''DynamoDB Streams''?','A way to watch movies from a database','An ordered sequence of item-level changes (insert, modify, delete) in a DynamoDB table, which can trigger Lambda functions for real-time processing','A ways to delete old data','none of the above','["B"]'::jsonb,'hard',45,'Streams are essential for building event-driven, reactive architectures based on data changes.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What happens in SNS ''Fan-out'' architecture?','The fans are turned on to cool the servers','A single message published to an SNS topic is automatically delivered to multiple endpoints (e.g. SQS queues, Lambda functions) simultaneously','A ways to delete users','none of the above','["B"]'::jsonb,'hard',45,'Fan-out is a powerful pattern for decoupling multiple disparate systems that all need the same event data.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''Amazon EventBridge''?','A bridge for events at the office','A serverless event bus that makes it easy to connect applications using data from your own apps, SaaS apps, and AWS services','A ways to rename files','none of the above','["B"]'::jsonb,'hard',45,'EventBridge is the modern successor to CloudWatch Events, offering better filtering and integration with SaaS partners.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What characterizes ''IAM Permission Boundaries''?','A wall around the user','An advanced feature where you use a managed policy to set the maximum permissions that an identity-based policy can grant to an IAM entity','A ways to delete a user','none of the above','["B"]'::jsonb,'hard',45,'Boundaries are used to delegate permission creation to developers safely by ensuring they can''t create ''admin'' level users.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','Which service helps protect against Layer 7 (application layer) attacks like SQL injection and cross-site scripting?','AWS Shield','AWS WAF','IAM','GuardDuty','["B"]'::jsonb,'hard',45,'WAF allows you to inspect web requests and block common patterns used in hacking attempts.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What characterizes an ''AWS VPN CloudHub''?','A hub for users to meet','A simple hub-and-spoke model for connecting multiple remote sites using AWS as the central hub, allowing sites to communicate with each other privately','A tool to delete old routers','none of the above','["B"]'::jsonb,'hard',45,'CloudHub is an economical way to use existing VPN connections for inter-branch communication.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What is ''Amazon FSx for Lustre''?','A ways to host pretty websites','A high-performance file system optimized for compute-intensive workloads like machine learning and high-performance computing (HPC)','A tool to delete files','none of the above','["B"]'::jsonb,'hard',45,'Lustre provides massive throughput and sub-millisecond latencies for parallel processing jobs.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What identifies ''Amazon Inspector'' Network Reachability scans?','Finding the user''s phone number','Agentless scans that analyze your VPC network configuration to find security vulnerabilities like open ports or unintended external access to your instances','A ways to name a router','none of the above','["B"]'::jsonb,'hard',45,'Reachability scans help ensure you don''t accidentally leave ''RDP'' or ''SSH'' open to the entire world.','pregenerated'),
('c8b0bcc5-a8da-4c65-bd8a-09b95f463f03','What characterizes ''Audit'' in CloudTrail?','Counting the users','Continuous, automated auditing of all account activity, providing a verifiable record for security analysis and compliance requirements','A ways to delete old files','none of the above','["B"]'::jsonb,'hard',45,'CloudTrail is the ''source of truth'' for when, who, and where an AWS action was initiated.','pregenerated')
INSERT INTO questions(level_id,question_text,option_a,option_b,option_c,option_d,correct_options,question_type,timer_seconds,explanation,source) VALUES
('931e0c93-4f3a-48ee-b505-0091350a61f6','How does ''AWS Transit Gateway'' handle VPC Peering limits at scale?','It increases the number of peering connections allowed','It acts as a network transit hub, using a hub-and-spoke model to simplify connectivity and scale to thousands of VPCs without a full-mesh peering requirement','It deletes the VPC peering limits','none of the above','["B"]'::jsonb,'hard',60,'Transit Gateway reduces operational complexity by centralizing routing logic and cross-account connectivity.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''Enhanced Networking'' on EC2 instances?','Buying a faster cable','Using SR-IOV (Single Root I/O Virtualization) to provide higher I/O performance and lower CPU utilization compared to traditional virtualized network interfaces','Naming the network ''Enhanced''','none of the above','["B"]'::jsonb,'hard',60,'Enhanced networking is critical for high-throughput, low-latency applications like financial modeling or big data processing.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is the primary benefit of ''DynamoDB Transactions''?','They make the database free','They provide atomicity, consistency, isolation, and durability (ACID) across multiple items within or across tables in a single AWS account and region','They are faster than standard writes','none of the above','["B"]'::jsonb,'hard',60,'Transactions are essential for all-or-nothing operations like financial transfers or inventory management.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','How does ''Amazon Aurora Global Database'' handle disaster recovery?','By using standard MySQL replication','By using storage-level fast replication to up to 5 secondary regions with typical latency of less than 1 second, enabling regional failover in minutes','By backup up to S3','none of the above','["B"]'::jsonb,'hard',60,'Global Database is designed for globally distributed applications and stringent RPO/RTO requirements.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Amazon S3 Batch Operations'' used for?','To name the files in a batch','To efficiently manage billions of objects at scale, performing actions like copying, restoring, or tagging across large sets of data in a single operation','A ways to delete old files','none of the above','["B"]'::jsonb,'hard',60,'Batch Operations eliminates the need to write custom scripts to process massive S3 datasets.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''AWS KMS Key Grants'' compared to ''Key Policies''?','Grants are for groups, Policies are for users','Key Policies are the primary mechanism for access control; Grants are a programmatic way to provide temporary, granular access to a key without modifying the key policy','Policies are for internal use, Grants are for external','none of the above','["B"]'::jsonb,'hard',60,'Grants are often used by AWS services (like EBS) to use your CMK on your behalf to encrypt volumes.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''AWS Lambda@Edge'' lifecycle hooks?','The function is called when the user logs in','Functions can be triggered at four distinct points: Viewer Request, Origin Request, Origin Response, and Viewer Response','The function is called when the server restarts','none of the above','["B"]'::jsonb,'hard',60,'Understanding these hooks is vital for implementing advanced edge logic like dynamic SEO or custom routing.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','Which SCP condition is used to enforce that resources can only be created in specific AWS regions?','aws:SourceIp','aws:RequestedRegion','aws:PrincipalOrgID','aws:CurrentTime','["B"]'::jsonb,'hard',60,'This condition is fundamental for data residency compliance and preventing ''shadow'' infrastructure in unauthorized regions.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is an ''AWS CloudFormation Macro''?','A ways to name a user','A feature that allows you to perform custom processing on templates (e.g. iterating over lists or including external data) using a Lambda function','A tool to delete old templates','none of the above','["B"]'::jsonb,'hard',60,'Macros allow for powerful template transformations and extending the native capabilities of CloudFormation.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is the purpose of ''AWS Private CA''?','To buy SSL certificates for the web','A managed private certificate authority service that helps you securely manage the lifecycle of private certificates for your internal resources (e.g. mTLS between services)','A ways to name a user','none of the above','["B"]'::jsonb,'hard',60,'Private CA is essential for Zero Trust architectures where every internal connection must be encrypted and authenticated.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''AWS Outposts'' local gateways?','A ways to name a router','A logical router that enables communication between your Outpost resources and your local, on-premises network with very low latency','A tool to delete physical cables','none of the above','["B"]'::jsonb,'hard',60,'Local gateways are the core component that allows Outposts to integrate with existing on-premises infrastructure seamlessly.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Amazon EMR Serverless''?','A ways to name a user','A serverless deployment option for EMR that makes it easy to run big data frameworks like Apache Spark and Hive without managing clusters or nodes','A tool to delete old clusters','none of the above','["B"]'::jsonb,'hard',60,'EMR Serverless handles the scaling and provisioning automatically, allowing you to pay only for the compute you use.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is a ''Rate-based Rule'' in AWS WAF using a ''Custom Key''?','A ways to name a user','A rule that counts the rate of specific requests based on custom identifiers (like a cookie value or Header instead of just IP) and blocks them if they exceed a limit','A ways to delete code','none of the above','["B"]'::jsonb,'hard',60,'Rate-based rules with custom keys are powerful for preventing brute-force or scraping attacks that rotate IPs.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','In the ''Security'' pillar of the Well-Architected Framework, what is ''Detachment of Personnel''?','Firing the employees','The principle of removing humans from data and direct access to production systems, relying on automated pipelines and immutable infrastructure instead','A ways to move servers','none of the above','["B"]'::jsonb,'hard',60,'Removing human access reduces the risk of accidental misconfiguration or malicious insider threats.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Route 53 Multi-value Answer'' routing?','Routing to the cheapest server','A routing policy that allows Route 53 to return multiple healthy IP addresses in response to a single DNS query, providing a simple form of load balancing','A ways to name a user','none of the above','["B"]'::jsonb,'hard',60,'Multi-value routing improves reliability by allowing the client''s browser to try a different IP if the first one fails.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''DynamoDB Adaptive Capacity''?','A ways to name a table','A feature that automatically reallocates throughput capacity in response to unbalanced workloads (hot partitions), preventing throttling for well-behaved partitions','A way to delete old data','none of the above','["B"]'::jsonb,'hard',60,'Adaptive capacity is a key reason why DynamoDB can handle massive, uneven load without constant manual tuning.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is an ''AWS Control Tower Guardrail''?','A physical fence at the office','A high-level rule (preventive or detective) that provides ongoing governance for your multi-account environment, such as ''Disallow public read to S3 buckets''','A ways to name a user','A tool to delete accounts','["B"]'::jsonb,'hard',60,'Guardrails are implemented using SCPs and AWS Config rules to enforce compliance across the whole organization.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''AWS Site-to-Site VPN Accelerated'' connection?','Buying a faster cable','A feature that uses AWS Global Accelerator to route your VPN traffic over the AWS global network rather than the public internet for the first leg of the journey','A ways to name a router','none of the above','["B"]'::jsonb,'hard',60,'Accelerated VPN significantly reduces latency and improves reliability for remote site connectivity.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''AWS Network Firewall''?','A wall made of routers','A managed service that provides high-availability network security (Layer 3-7) to protect your VPCs, including features like stateful inspection, intrusion prevention (IPS), and web filtering','A tool to delete old code','none of the above','["B"]'::jsonb,'hard',60,'Network Firewall replaces complex, self-managed firewall appliances with a native cloud service.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''EC2 Spot Fleet''?','A bunch of fast cars','A service that manages the launching and maintaining of a specified target capacity of Spot instances (and optionally On-Demand) across multiple instance types and AZs','A tool to delete servers','none of the above','["B"]'::jsonb,'hard',60,'Spot Fleets are an extremely cost-effective way to run large-scale compute workloads like data processing or rendering.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is the role of ''AWS DataSync'' in large-scale migrations?','To name the files','A managed data transfer service that simplifies, automates, and accelerates moving and replicating data between on-premises storage and AWS storage services (S3, EFS, FSx)','A tool to delete old files','none of the above','["B"]'::jsonb,'hard',60,'DataSync can handle massive data sets much faster than standard open-source tools like rsync.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What defines ''AWS App Mesh''?','A mesh for the office windows','A service mesh that provides application-level networking to make it easy for your services to communicate with each other across multiple types of compute infrastructure','A tool to delete old code','none of the above','["B"]'::jsonb,'hard',60,'App Mesh provides consistent visibility, high availability, and network traffic control for every microservice in your stack.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''AWS CloudHSM''?','A ways to hide money','A cloud-based hardware security module (HSM) that enables you to easily generate and use your own encryption keys in AWS using FIPS 140-2 Level 3 validated hardware','A tool to delete old keys','none of the above','["B"]'::jsonb,'hard',60,'CloudHSM is required for customers who need physical control over their keys for regulatory compliance.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Amazon Keyspaces''?','A ways to name a user','A scalable, highly available, and managed Apache Cassandra-compatible database service','A tool to delete old tables','none of the above','["B"]'::jsonb,'hard',60,'Keyspaces allows you to run your Cassandra workloads on AWS using the same Cassandra Query Language (CQL) code.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Amazon SageMaker Ground Truth''?','A ways to find the truth','A fully managed data labeling service that makes it easy to build highly accurate training datasets for machine learning','A tool to delete old models','none of the above','["B"]'::jsonb,'hard',60,'Ground Truth uses a combination of human workers and machine learning to produce high-quality labels at scale.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''Amazon EC2 Auto Scaling'' Predictive Scaling?','Guessing the next user','A feature that uses machine learning to analyze historical traffic patterns and proactively schedule changes in the number of EC2 instances in anticipation of future demand','A tool to delete old servers','none of the above','["B"]'::jsonb,'hard',60,'Predictive scaling ensures the capacity is already there when the users arrive, rather than reacting after the fact.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What defines ''Amazon S3 Replication Time Control'' (RTC)?','A ways to stop time','A feature that provides an SLA-backed guarantee to replicate 99.99% of your new S3 objects within 15 minutes of upload','A tool to delete old versions','none of the above','["B"]'::jsonb,'hard',60,'RTC is vital for business-critical applications that require predictable data durability and replication.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''AWS Transit Gateway Multicast''?','A ways to name a user','A feature that enables you to deliver a single stream of information to many recipients simultaneously in the cloud, which was traditionally hard to do in VPCs','A tool to delete routers','none of the above','["B"]'::jsonb,'hard',60,'Multicast is used for specific workloads like financial ticker data or video streaming.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''AWS Directory Service'' AD Connector?','A ways to connect a computer','A proxy service that enables you to use your existing on-premises Active Directory identities with AWS applications without requiring complex synchronization','A tool to delete old users','none of the above','["B"]'::jsonb,'hard',60,'AD Connector is a simple way to bring SSO and IAM federation to your corporate environment.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','In the ''Reliability'' pillar of the Well-Architected Framework, what is ''Design for Failure''?','Trying to fail','The practice of assuming that every individual component will eventually fail and designing the system to handle those failures without losing service','A ways to delete old code','none of the above','["B"]'::jsonb,'hard',60,'Design for failure leads to architectures using Multi-AZ, retries, and decoupled messaging.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Amazon Aurora Clone''?','A ways to clone a user','A feature that allows you to create a new, independent copy of an Aurora database cluster very quickly, using a copy-on-write mechanism that only consumes storage for changes','A tool to delete old tables','none of the above','["B"]'::jsonb,'hard',60,'Cloning is perfect for spinning up test or analytics environments from production data without any performance impact or cost overhead.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''AWS CloudFormation Custom Resources''?','A ways to name a user','A mechanism that allows you to write custom provisioning logic (using Lambda) to manage resources that are NOT natively supported by CloudFormation','A tool to delete old stacks','none of the above','["B"]'::jsonb,'hard',60,'Custom resources allow you to manage third-party APIs or complex configurations as part of your stack lifecycle.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What defines ''AWS Migration Evaluator'' (formerly TSO Logic)?','A ways to name a migration','A free service to create a data-driven business case for AWS migration, providing clear visibility into your current estate and projected AWS costs','A tool to delete old servers','none of the above','["B"]'::jsonb,'hard',60,'Migration Evaluator helps leadership teams make informed financial decisions about moving to the cloud.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''AWS Cloud9''?','A ways to name a cloud','A cloud-based integrated development environment (IDE) that lets you write, run, and debug your code with just a browser','A tool to delete old code','none of the above','["B"]'::jsonb,'hard',60,'Cloud9 comes pre-packaged with essential tools for building serverless applications on AWS.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''AWS Client VPN''?','A ways to name a user','A fully managed, client-based VPN service that enables you to securely access your AWS resources and your on-premises network from anywhere','A tool to delete old routers','none of the above','["B"]'::jsonb,'hard',60,'Client VPN uses OpenVPN and integrates with SAML for secure, flexible remote worker access.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Amazon Redshift RA3'' instances?','A ways to name a cluster','Instances that allow you to scale and pay for compute and storage independently, using S3 for a managed storage layer','A tool to delete old data','none of the above','["B"]'::jsonb,'hard',60,'RA3 instances solve the problem of having to add more compute just because you need more disk space.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What defines ''AWS Resource Access Manager'' (RAM)?','A ways to hide money','A service that enables you to easily and securely share your AWS resources (like Transit Gateways or Subnets) with any AWS account or within your AWS Organization','A tool to delete old resources','none of the above','["B"]'::jsonb,'hard',60,'RAM eliminates the need for complex cross-account roles when sharing foundational networking components.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Amazon FSx for OpenZFS''?','A ways to host pretty websites','A fully managed, highly reliable, and scalable file storage that is built on the open-source OpenZFS file system, providing NFS-compatible shared storage','A tool to delete old files','none of the above','["B"]'::jsonb,'hard',60,'FSx for OpenZFS is ideal for moving on-premises ZFS workloads to AWS with minimal changes.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What characterizes ''EC2 Nitro System''?','A ways to speed up servers with gas','A collection of purpose-built hardware and a lightweight hypervisor that offloads virtualization functions to dedicated hardware, maximizing performance for guests','A tool to delete old servers','none of the above','["B"]'::jsonb,'hard',60,'The Nitro system is the core innovation that allows AWS to offer bare-metal-like performance on virtual machines.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What defines ''AWS Security Hub''?','A ways to name a user','A cloud security posture management (CSPM) service that performs security best practice checks, aggregates alerts, and enables automated remediation','A tool to delete old alerts','none of the above','["B"]'::jsonb,'hard',60,'Security Hub provides a comprehensive view of your security state across all your AWS accounts.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','How can you implement a ''Cell-based architecture'' to increase the fault tolerance of a massive scale application?','By using smaller batteries for servers','By partitioning the application into smaller, independent, and isolated ''cells'' that do not share state, limiting the blast radius of any failure','By using a larger database','By increasing the timeout of load balancers','["B"]'::jsonb,'hard',45,'Cell-based architectures are used by hyper-scale applications to ensure that a failure in one cell doesn''t affect users in others.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','When using AWS Transit Gateway, how is ''Inter-Region Peering'' traffic charged?','It is free','Standard data transfer charges apply based on the amount of data sent between regions','By the number of packets only','It is included in the S3 price','["B"]'::jsonb,'hard',45,'Data transfer between Transit Gateways in different regions follows standard AWS inter-region data transfer rates.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is the primary benefit of ''Attribute-Based Access Control'' (ABAC) in IAM?','It uses passwords instead of keys','It allows for dynamic scaling of permissions based on tags, reducing the need for unique policies for every user and resource','It is faster than standard IAM','It encrypts the IAM console','["B"]'::jsonb,'hard',45,'ABAC uses tags (attributes) to make authorization decisions, making it easier to manage permissions as teams grow.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','Which EBS volume type is designed for mission-critical, high-performance workloads with low latency and sustained IOPS?','General Purpose (gp3)','Provisioned IOPS (io2 Block Express)','Cold HDD (sc1)','Throughput Optimized HDD (st1)','["B"]'::jsonb,'hard',45,'io2 Block Express is the highest performing block storage in the cloud, offering up to 256,000 IOPS per volume.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','In a ''Warm Standby'' DR strategy, what is the state of the DR environment?','Turned off completely','A scaled-down but functional version of the production environment always running in a different region','Just a small server to receive heartbeats','Exactly the same size as production','["B"]'::jsonb,'hard',60,'Warm standby reduces recovery time compared to Pilot Light by having minimum resources already running.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Amazon Aurora Global Write Forwarding''?','A ways to skip region checks','A feature that allows read replicas in secondary regions to forward write requests to the primary region, simplifying application logic','A tool to delete secondary databases','A ways to naming databases','["B"]'::jsonb,'hard',45,'Write forwarding makes it easier to build globally distributed applications that need to write back to a central DB.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','How does ''AWS Nitro Enclaves'' provide a secure compute environment?','By using a stronger firewall','By creating isolated compute environments that have no persistent storage, no interactive access, and only a secure local channel to the parent instance','By encrypting the CPU','By running servers in a bunker','["B"]'::jsonb,'hard',45,'Nitro Enclaves allow you to process highly sensitive data in a cryptographically isolated and secure environment.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Amazon Redshift RA3'' instance type''s key innovation?','Faster RAM','Decoupling of compute and storage, allowing you to scale each independently','Free storage for 1 month','A smaller CPU','["B"]'::jsonb,'hard',45,'RA3 instances use high-speed cache and S3-backed storage to allow massive scaling without scaling compute unnecessarily.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','How do ''AWS Outposts'' interact with the local data center''s internet connection?','They don''t; they use satellite','They use a local gateway (LGW) to route traffic directly to the on-premises network or local internet','They must route all traffic back to the AWS Region first','They use dial-up','["B"]'::jsonb,'hard',45,'Local gateways provide low-latency connectivity to local workloads and the internet without leaving the data center.','pregenerated'),
('931e0c93-4f3a-48ee-b505-0091350a61f6','What is ''Lambda Provisioned Concurrency'' designed to solve?','High costs','Cold start latency for applications requiring consistent low latency','Max function size','Encryption bugs','["B"]'::jsonb,'hard',30,'Provisioned concurrency keeps a specified number of execution environments warm and ready to respond.','pregenerated')
INSERT INTO questions(level_id,question_text,option_a,option_b,option_c,option_d,correct_options,question_type,timer_seconds,explanation,source) VALUES
('100647d4-a942-4561-b126-57482c10b96e','In the C memory layout, where are local variables typically stored?','Heap','Stack','Data Segment','Code Segment','["B"]'::jsonb,'easy',20,'Local variables are stored in the stack frame of the function.','pregenerated'),
('100647d4-a942-4561-b126-57482c10b96e','Which storage class is used for global variables by default?','auto','register','extern','static','["C"]'::jsonb,'easy',20,'Global variables have external linkage and are conceptually ''extern'' by default.','pregenerated'),
('100647d4-a942-4561-b126-57482c10b96e','What is the result of ''5 + 3 * 2'' in C?','16','11','13','10','["B"]'::jsonb,'easy',20,'Multiplication has higher precedence than addition.','pregenerated'),
('100647d4-a942-4561-b126-57482c10b96e','Which segment stores uninitialized global variables?','BSS','Stack','Heap','Text','["A"]'::jsonb,'easy',20,'BSS (Block Started by Symbol) stores uninitialized global and static variables.','pregenerated'),
('100647d4-a942-4561-b126-57482c10b96e','What does the ''static'' keyword do to a local variable?','Makes it constant','Preserves its value between function calls','Moves it to the heap','Makes it accessible globally','["B"]'::jsonb,'easy',20,'Static local variables retain their values across multiple calls to the same function.','pregenerated'),
('100647d4-a942-4561-b126-57482c10b96e','Which operator has the highest precedence among these?','+','++','=','==','["B"]'::jsonb,'easy',20,'Increment/Decrement (++) has higher precedence than arithmetic or assignment operators.','pregenerated'),
