('700f5038-5b59-4c7e-9204-70ab7365c5e6','What results from `ptr1 - ptr2` if they are in different arrays?','Number of bytes between them','Undefined behavior','Total memory size','Linker error','["B"]'::jsonb,'tricky',30,'Pointer subtraction is only defined for pointers within the same contiguous memory block (array).','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Pointers enable which of these programming paradigms in C?','Dynamic memory allocation','Efficient data structure handling','Call by reference','All of the above','["D"]'::jsonb,'core_concept',30,'Pointers are fundamental for memory management, speed, and function flexibility in C.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','When a pointer is incremented, its value increases by:','1 always','The size of the pointed-to object','The size of the pointer itself','Depends on the CPU','["B"]'::jsonb,'core_concept',30,'Pointer arithmetic is scaled by the size (in bytes) of the data type it references.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','The array name acts as:','A pointer to the whole array','A pointer to its first element','A constant data value','A function','["B"]'::jsonb,'core_concept',30,'In most contexts, the array name ''decays'' to a pointer to the 0th element.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Which of these is used to invoke a function via its pointer?','f_ptr();','(*f_ptr)();','Both A and B','f_ptr->();','["C"]'::jsonb,'core_concept',30,'Either the explicit dereference or the direct name invocation works for function pointers.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Dereferencing which pointer type leads to evaluation error?','char*','void*','int*','float*','["B"]'::jsonb,'core_concept',30,'Void pointers don''t have associated size, so they cannot be dereferenced directly.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','The memory address stored in the pointer is typically:','Virtual address','Physical address','Logical register','Relative offset','["A"]'::jsonb,'core_concept',30,'Modern C programs work with virtual addresses provided by the operating system.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Initialization `int *p = NULL;` is recommended because:','It clears the memory','It prevents hard-to-debug wild pointer crashes','It sets the size to zero','It calls the garbage collector','["B"]'::jsonb,'core_concept',30,'Initializing pointers to NULL makes it easy to check if they are currently valid.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Accessing `arr[i]` is faster than `*(arr+i)`?','True','False, they are identical to the compiler','True, only for small arrays','Depends on optimization','["B"]'::jsonb,'core_concept',30,'To a C compiler, arr[i] is just a syntactic sugar for *(arr + i).','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Which of these are valid operations on pointers?','Addition of two pointers','Subtraction of an integer from a pointer','Comparison with NULL','Comparison of two pointers to the same array','["B","C","D"]'::jsonb,'multi_correct',30,'Subtracting int, checking for NULL, and comparing related pointers are all valid.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','What happens when you use an array name ''arr'' in a function call `func(arr)`?','Passed by value (entire array copied)','Passed by address (pointer to 1st element)','Information about array size is lost','Pointer decay occurs','["B","C","D"]'::jsonb,'multi_correct',30,'Arrays decay to pointers during function calls; size info must be passed separately.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Which of these correctly declare a pointer?','int *ptr;','int* ptr;','int * ptr;','void* ptr;','["A","B","C","D"]'::jsonb,'multi_correct',30,'C is flexible with whitespace between ''int'', ''*'', and the variable name.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Characteristics of double pointers (int **p):','Stores address of another pointer','Required to modify pointer values in functions','Can represent dynamic 2D structures','Twice as large as normal pointers','["A","B","C"]'::jsonb,'multi_correct',30,'Double pointers store addresses of other pointers; their size is the same as single pointers.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Which of these can prevent pointer-related crashes?','Null check before dereferencing','Setting pointer to NULL after free()','Always using void*','Initializing pointers during declaration','["A","B","D"]'::jsonb,'multi_correct',30,'Robust checks, clearing after free, and proper initialization are key practices.','pregenerated'),
('700f5038-5b59-4c7e-9204-70ab7365c5e6','Identify valid array/pointer notation equivalences:','arr[1][2] == *(*(arr+1)+2)','&arr[0] == arr','arr[0] == *arr','arr+1 == &arr[1]','["A","B","C","D"]'::jsonb,'multi_correct',30,'These are all standard C equivalences for multi-dimensional and 1D arrays.','pregenerated')
INSERT INTO questions(level_id,question_text,option_a,option_b,option_c,option_d,correct_options,question_type,timer_seconds,explanation,source) VALUES
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which function is used to allocate memory dynamically but does NOT initialize it?','calloc','malloc','realloc','alloc','["B"]'::jsonb,'easy',30,'malloc allocates a block of uninitialized memory on the heap.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What does ''calloc'' do besides allocating memory?','Frees previous memory','Sets all bits to zero','Checks for errors only','Encrypts the data','["B"]'::jsonb,'easy',30,'calloc initializes the allocated memory block to zeros.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which standard library defines malloc and free?','stdio.h','string.h','stdlib.h','conio.h','["C"]'::jsonb,'easy',30,'Memory management functions are part of the C Standard Library (stdlib.h).','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What is the correct return type of malloc?','int*','void*','char*','NULL','["B"]'::jsonb,'easy',30,'malloc returns a generic void pointer that can be cast to any type.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','To open a file for writing in C, which mode string is used in ''fopen''?','r','a','w','x','["C"]'::jsonb,'easy',30,'''w'' stands for write mode (overwrites if file already exists).','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What does `fclose(fptr)` return on success?','1','-1','0','NULL','["C"]'::jsonb,'easy',30,'fclose returns 0 for success and EOF on error.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which function reads a single character from a file?','fputc','fgetc','gets','scanf','["B"]'::jsonb,'easy',30,'fgetc is used to read a character from the specified file stream.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What is ''EOF'' typical integer value?','0','1','-1','100','["C"]'::jsonb,'easy',30,'EOF is usually defined as -1 in stdio.h.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','If malloc fails to allocate memory, it returns:','0','NULL','Garbage','Runtime Exception','["B"]'::jsonb,'easy',30,'NULL is returned when the heap cannot fulfill the memory request.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What is the difference between malloc(n) and calloc(1, n)?','Malloc is faster','Calloc initializes to zero','There is no difference','Malloc requires two arguments','["B"]'::jsonb,'medium',30,'Both allocate the same amount of memory, but calloc initializes it to zero.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What happens if you use ''realloc'' with a size of 0?','Allocates 1 byte','Equivalent to free() in legacy C','Does nothing','Double frees memory','["B"]'::jsonb,'medium',30,'Calling realloc(ptr, 0) behaves like free(ptr) in many C implementations.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which mode string opens file for reading and writing (append)?','a+','r+','w+','rw','["A"]'::jsonb,'medium',30,'''a+'' opens for reading and appending to the end of the file.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What does `rewind(fptr)` do?','Closes the file','Moves cursor to the start of the file','Deletes file content','Reopens file in write mode','["B"]'::jsonb,'medium',30,'rewind() resets the file position indicator to the beginning of the file.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which function is best for writing a structure to a file?','fprintf','fwrite','fputc','fputs','["B"]'::jsonb,'medium',30,'fwrite outputs block data (binary), ideal for structures.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What is the return type of `ftell`?','int','long','FILE*','void','["B"]'::jsonb,'medium',30,'ftell returns the current file position as a long integer.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','How do you free memory allocated for a 2D array built as array of pointers?','free(arr);','Free each row, then the outer pointer','Use free_2d(arr);','It frees itself when function ends','["B"]'::jsonb,'medium',30,'Every malloc call needs its own corresponding free call.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which mode Opens a binary file only for reading?','r','rb','rt','only_read','["B"]'::jsonb,'medium',30,'''rb'' indicates read mode for binary files.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Does `free(NULL)` cause a crash?','Yes','No, it does nothing','Only on Linux','Depends on the data type','["B"]'::jsonb,'medium',30,'The standard C specification states that free(NULL) has no effect.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What happens if ''realloc'' cannot expand the memory block in place?','It fails and returns NULL','It allocates a new block, copies data, and frees old block','It waits until space is available','It overwrites adjacent memory','["B"]'::jsonb,'hard',60,'realloc finds a new location if the current one cannot be resized, handles copy and free.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','If `fseek(fptr, 0, SEEK_END)` returns 0, what does `ftell(fptr)` give?','0','Total file size in bytes','Pointer to the end','EOF','["B"]'::jsonb,'hard',60,'fseek to the end makes the cursor point at the very last position, which is the file size.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Why check the return of realloc using a temporary pointer?','Efficiency','To prevent memory leak if NULL is returned','Syntax requirements','To avoid compiler warnings','["B"]'::jsonb,'hard',60,'If realloc fails and you assign NULL directly to the original pointer, you lose reference to old memory.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which function is used for buffered file I/O flushing?','freset','fflush','fclear','fclean','["B"]'::jsonb,'hard',60,'fflush forces the writing of buffered output data to the disk.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','A program uses malloc but never calls free. What occurs?','Segmentation fault','Memory leak','Automatic garbage collection','CPU usage spike','["B"]'::jsonb,'hard',60,'Memory stays allocated until the process dies, reducing available system memory.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','How do you check for end-of-file after reading using `feof`?','Before the read operation','After a read attempt failed','Immediately when opening file','Only for binary files','["B"]'::jsonb,'hard',60,'feof is only set after a read operation tries to read past the end of file.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What is the second parameter of `fread`?','File pointer','Size of each element to read','Number of elements','Buffer address','["B"]'::jsonb,'hard',60,'fread(buffer, size, count, file_ptr); the 2nd param is size of one record.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Can malloc allocate memory for zero bytes?','Illegal, returns NULL','Implementation defined (NULL or unique pointer)','Infinite loop','Always returns address 0x1','["B"]'::jsonb,'hard',60,'The behavior of malloc(0) depends on the implementation, but it shouldn''t crash.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which error flag should be cleared if you want to retry reading from a file?','EOF','clearerr()','clreof()','resetf()','["B"]'::jsonb,'hard',60,'clearerr() resets the EOF and error indicators for a stream.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What happens if you `free` the same pointer twice?','Memory is doubly freed','Undefined behavior (often crash)','Ignore second time','Compiles but doesn''t run','["B"]'::jsonb,'tricky',60,'Double freeing leads to memory corruption and undefined behavior.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Result of `p = malloc(10); p++; free(p);`?','Frees last 9 bytes','Undefined behavior/Runtime crash','Memory leak of 1 byte','Correct code','["B"]'::jsonb,'tricky',60,'You must pass the exact address returned by malloc to free; modifying p before free is an error.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What''s wrong with: `FILE *f; f = fopen("t.txt", "r"); if (f == EOF)...`?','EOF is not a pointer type','Should check for NULL','Both A and B','Nothing','["C"]'::jsonb,'tricky',60,'fopen returns NULL on failure; EOF is an integer constant for char reading.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What value does `fseek(f, -5, SEEK_SET)` lead to?','Start of file','End of file','Undefined behavior / error','Wrap around to end','["C"]'::jsonb,'tricky',60,'You cannot seek to a negative position relative to the start of the file.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What happens to data in realloc if the new size is smaller than the old one?','All data is lost','Data is truncated to the new size','Expansion error','Memory leak','["B"]'::jsonb,'tricky',60,'Data within the smaller size is preserved; excess data is discarded.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Difference between `printf` and `fprintf`?','fprintf is faster','fprintf allows output to any file stream','printf only works for strings','fprintf is for binary only','["B"]'::jsonb,'tricky',60,'printf is a wrapper around fprintf(stdout, ...).','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','How do you read a line with spaces from a file safely?','scanf("%s")','fgets','gets','fread','["B"]'::jsonb,'tricky',60,'fgets() is safe as it limits the number of characters read and handles spaces.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What is `SEEK_CUR`?','Moves cursor to specific byte','Offset from current cursor position','Clears the cursor','Pointer to the cursor','["B"]'::jsonb,'tricky',60,'SEEK_CUR is used in fseek to move relative to the current file pointer.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which segment does malloc interact with?','BSS','Stack','Heap','Text','["C"]'::jsonb,'tricky',60,'The ''heap'' is the memory pool for dynamic memory requests.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Manual memory management in C is important because:','C has no garbage collector','It gives fine control over performance','Both A and B','It prevents syntax errors','["C"]'::jsonb,'core_concept',60,'C relies on the programmer to free heap memory, offering maximum efficiency at the cost of safety.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Why do we use ''void*'' for malloc''s return?','To waste memory','So it can be cast to any pointer type','Because void is larger than int','To indicate it belongs to the CPU','["B"]'::jsonb,'core_concept',60,'malloc is generic and doesn''t know what kind of data you will store.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What is the primary risk of using ''gets()''?','Slow performance','Buffer overflow','Linker failure','Memory fragmentation','["B"]'::jsonb,'core_concept',60,'gets() doesn''t check buffer limits, making it highly insecure.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Binary files vs Text files in C:','Binary stores bytes directly; Text uses character encoding','Text is faster','Binary files are read-only','Text files cannot be dynamic','["A"]'::jsonb,'core_concept',60,'Binary files store raw data bits, while text files are processed into readable chars (like handling newlines).','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What is a ''FILE'' type in C?','An array of chars','A specific identifier for external disk space','A structure holding stream info','A primitive numeric type','["C"]'::jsonb,'core_concept',60,'FILE is an opaque structure containing buffers, error flags, and current positions for a stream.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Memory fragmentation is caused by:','Pointers being NULL','Repeated inconsistent malloc/free calls leaving ''holes''','Fast CPU speeds','Using long instead of int','["B"]'::jsonb,'core_concept',60,'Allocating and freeing different sizes can leave small unusable gaps in the heap.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Buffer in file I/O helps by:','Compressing data','Reducing expensive physical disk operations','Formatting the string','Encrypting the file','["B"]'::jsonb,'core_concept',60,'Reading/writing in chunks (buffering) is much faster than byte-by-byte disk access.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which condition indicates `malloc` was successful?','ptr == NULL','ptr != NULL','ptr == 0','*ptr == 0','["B"]'::jsonb,'core_concept',60,'Checking that the returned pointer is not NULL confirms allocation success.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which functions provide block-wise dynamic allocation?','malloc','calloc','realloc','memset','["A","B","C"]'::jsonb,'multi_correct',60,'malloc, calloc, and realloc all request blocks from the heap; memset just modifies existing memory.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Identify standard file streams in C:','stdin','stdout','stderr','stdlog','["A","B","C"]'::jsonb,'multi_correct',60,'There are three predefined standard streams: input, output, and error.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which modes create a new file if it doesn''t already exist?','w','a','r','w+','["A","B","D"]'::jsonb,'multi_correct',60,'Write and Append modes create files. Read mode fails if file is missing.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','What can happen if heap memory is not freed properly?','Memory Leaks','Performance Degradation','Process termination by OS due to memory pressure','Hard drive disk failure','["A","B","C"]'::jsonb,'multi_correct',60,'Inadequate freeing consumes RAM, slows systems, and leads to crashes, but doesn''t break hardware.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Which functions can be used to set a file pointer?','fseek','rewind','ftell','setsession','["A","B"]'::jsonb,'multi_correct',60,'fseek and rewind change the position; ftell only reports it.','pregenerated'),
('72e94b8e-9ffe-4111-8b7c-0497317c116a','Valid ways to write data to a file:','fprintf(f, "...")','fputs("...", f)','fgetc(f)','fwrite(&data, size, count, f)','["A","B","D"]'::jsonb,'multi_correct',60,'fprintf, fputs, and fwrite are output functions; fgetc is for input.','pregenerated')
INSERT INTO questions(level_id,question_text,option_a,option_b,option_c,option_d,correct_options,question_type,timer_seconds,explanation,source) VALUES
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is the keyword used to define a structured data type in C?','Class','struct','union','object','["B"]'::jsonb,'easy',30,'Struct is the keyword for creating a user-defined data type that groups different variables.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','How do you access a structure member through a pointer?','.','*','->','&','["C"]'::jsonb,'easy',30,'The arrow operator (->) is shorthand for dereferencing a pointer and accessing a member.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is the primary difference between a struct and a union in terms of memory?','Struct is larger','Union members share the same memory location','Struct is for strings only','Unions are not allowed in C','["B"]'::jsonb,'easy',30,'In a union, all members start at the same memory address, whereas struct members are sequential.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Which operator is used to determine the memory size of a structure?','countof','sizeof','lengthof','memsize','["B"]'::jsonb,'easy',30,'sizeof structure_name returns the total bytes required by that structure.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is the size of a bit-field declared as `unsigned int x : 1;`?','1 byte','1 bit (conceptually)','4 bytes','Compiler dependent','["B"]'::jsonb,'easy',30,'Bit-fields allow specifying the exact number of bits used by a member.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','To manipulate specific hardware registers, pointers are usually marked as:','const','static','volatile','register','["C"]'::jsonb,'easy',30,'volatile prevents the compiler from optimizing out repeated reads/writes to hardware addresses.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Can a structure contain another structure within it?','Yes, nested structures are allowed','No','Only if defined as pointers','Only for recursive structs','["A"]'::jsonb,'easy',30,'C supports nesting of structures inside one another.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What does `typedef` do?','Allocates memory','Creates an alias for an existing type','Defines a new variable','Initializes a struct','["B"]'::jsonb,'easy',30,'typedef makes code cleaner by providing shorter names for complex types like structs.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Which segment stores global structured variables?','Stack','Data/BSS segment','Heap','Register file','["B"]'::jsonb,'easy',30,'Global structs behave like global variables and are placed in data or BSS segments.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','If `union U { int x; char y; } u;`, what happens if you set `u.x = 65;` and read `u.y`?','Garbage','65 (''A'' in ASCII)','Crash','y is zero','["B"]'::jsonb,'medium',30,'Unions share memory, so modifying x also affects the bytes seen through y.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is ''Padding'' in structures?','Adding spaces to strings','Non-used bytes added by compiler for alignment','Initial zeroing of struct','Buffer protection','["B"]'::jsonb,'medium',30,'Compilers add padding bytes to ensure members are aligned on word boundaries for efficiency.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Can bit-fields be used with any data type?','No, only integer types (int, signed, unsigned)','Yes, including floats','Only with pointers','Yes, with structs','["A"]'::jsonb,'medium',30,'Bit-fields must be declared using integral types.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Why do unions save memory?','They compress data','They allocate memory for only the largest member','They use short integers only','They reside in the registers','["B"]'::jsonb,'medium',30,'The size of a union is determined by its largest component.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','In `struct { int x : 3; } s;`, what is the maximum value for `s.x`?','3','7 (assuming unsigned)','15','depends on size of int','["B"]'::jsonb,'medium',30,'3 bits can store 2^3 colors (0-7 for unsigned).','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is a ''Self-referential structure''?','A structure that contains a pointer to itself','A structure that inherits from itself','A structure with only one member','An illegal construct in C','["A"]'::jsonb,'medium',30,'These are used for Linked Lists and Trees (e.g., struct Node { struct Node *next; }).','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Memory alignment helps in:','Faster CPU access to data','Saving disk space','Encapsulation','Recursive calls','["A"]'::jsonb,'medium',30,'Aligned data can be fetched in fewer bus cycles by most processors.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Are structs passed by value or by reference in C?','By value (entire struct copied) by default','By reference always','Only pointers are passed','Recursive copying occurs','["A"]'::jsonb,'medium',30,'Passing a struct directly creates a full copy of the entire structure.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is a ''Flexible Array Member''?','An array that changes size automatically','An unsized array as the last member of a struct','A dynamic array on stack','A pointer to an array','["B"]'::jsonb,'medium',30,'Allows structs to have variable-sized data at the end (introduces C99).','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Which attribute can be used in GCC to avoid structure padding?','__attribute__((packed))','#pragma nopad','struct_compact','tighten(struct)','["A"]'::jsonb,'hard',60,'__attribute__((packed)) tells the compiler to use minimum space, ignoring alignment.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Can you take the address of a bit-field member?','No, bit-fields don''t have byte-aligned addresses','Yes, using &','Only if size is 8 bits','Only for char bit-fields','["A"]'::jsonb,'hard',60,'The & operator cannot be used on bit-fields because they may not start on a byte boundary.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is the endianness problem in hardware interfacing?','Structure size mismatch','Order of bytes in multi-byte types (Big-Endian vs Little-Endian)','Padding inconsistency','Voltage levels','["B"]'::jsonb,'hard',60,'Different systems store the most significant byte differently, affecting cross-hardware communication.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','A union containing three members of size 2, 4, and 8 bytes respectively will occupy how many bytes?','14','8','4','16 (due to alignment)','["B"]'::jsonb,'hard',60,'Union size is the size of its largest member; alignment might increase it slightly but 8 is base.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','How do you map a structure to a specific hardware memory address 0x4000?','struct my_reg *r = (struct my_reg *)0x4000;','r = open_reg(0x4000);','Hard-coding in the struct definition','It''s impossible in standard C','["A"]'::jsonb,'hard',60,'Casting an integer literal to a struct pointer is standard for memory-mapped I/O.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is the purpose of anonymous unions inside a structure?','Memory security','Directly accessing union members without naming the union','Naming conflicts','To hide data from debugger','["B"]'::jsonb,'hard',60,'Anonymous unions allow members to be accessed like direct struct members.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Can a struct containing a pointer to itself be initialized?','Yes, by setting the pointer to NULL','No, it causes infinite loop in memory','Only if defined as static','Only in C++','["A"]'::jsonb,'hard',60,'Initialization works fine; the pointer just stores an address (or NULL).','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Alignment ''offset'' is often calculated using which macro?','sizeof','offsetof','ptr_offset','memb_pos','["B"]'::jsonb,'hard',60,'offsetof from stddef.h provides the byte offset of a member within a struct.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','In bit-fields, what is the effect of an unnamed field with 0 width?','Compiler error','Forces alignment to the next storage unit boundary','Does nothing','Clears the struct','["B"]'::jsonb,'hard',60,'An unnamed bit-field with size 0 aligns the next field to a new underlying type boundary.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What happens if a struct is assigned to another struct of the same type?','Only pointers are copied','Member-wise copy occurs (deep copy for non-pointers)','Error','Only first member is copied','["B"]'::jsonb,'tricky',60,'Assignment of structs performs a bitwise/member-wise copy of everything in the struct.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Is `sizeof` structure calculated before or after padding?','Before','After (includes padding)','Compiler chooses','Structure size never has padding','["B"]'::jsonb,'tricky',60,'sizeof returns the total footprint in memory, including all alignment padding.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','In a union, which member gets destroyed when a new one is assigned?','The smallest one','The largest one','None, they are overlapped; previous data is corrupted','C has garbage collection for unions','["C"]'::jsonb,'tricky',60,'Unions do not manage ''active'' members; writing to one just overwrites the common memory space.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What happens to the remaining bits in a byte if bit-fields don''t fill it?','Used for the next variable','Padding','Left uninitialized','Cause a crash','["B"]'::jsonb,'tricky',60,'Compilers normally fill remaining bits in a word with padding or leave them unused.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Can we have an array of bit-fields?','Yes','No, bit-fields don''t have standard addresses','Only for single bits','Depends on the CPU','["B"]'::jsonb,'tricky',60,'Standard C forbids arrays of bit-fields because each element wouldn''t have a byte-aligned address.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is result of `struct S { int a; } s1, s2; s1.a=10; s2=s1; s1.a=20;` what is `s2.a`?','10','20','Garbage','Error','["A"]'::jsonb,'tricky',60,'Struct assignment copies the values; they are independent copies in memory.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','A structure pointer being 0x0 is essentially:','Pointing to the code segment','A NULL pointer','A void struct','Illegal definition','["B"]'::jsonb,'tricky',60,'0x0 is interpreted as NULL by the C standard for all pointer types.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Does C guarantee the order of members in a structure in memory?','Yes, in the order they are declared','No, the compiler can reorder for space','Only for unions','Only for packing','["A"]'::jsonb,'tricky',60,'The order of struct members in memory must match their declaration order (ignoring padding).','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Are local struct variables initialized automatically?','Yes, to zero','No, they contain garbage','Only the pointer is NULL','Only bit-fields are 0','["B"]'::jsonb,'tricky',60,'Automatic (local) structures, like primitive variables, are uninitialized by default.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Structures provide a way to implement:','Data Encapulation (logical grouping)','Recursive data types (links, trees)','Memory-mapped I/O registers','All of the above','["D"]'::jsonb,'core_concept',60,'Structs are versatile for grouping info, building complex nodes, and mapping hardware.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','The memory overhead of a structure is usually due to:','The struct keyword itself','Alignment padding','Member pointers','Recursive references','["B"]'::jsonb,'core_concept',60,'Padding to align members with processor word boundaries increases struct size.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Unions are primarily used for:','Polymorphism (treating same data as different types)','Memory optimization (mutually exclusive data)','Both A and B','Faster file I/O','["C"]'::jsonb,'core_concept',60,'Unions allow data interpretation in multiple ways and save space for items never used together.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Volatile keyword is critical for hardware because:','Registers can change independently of code (due to hardware events)','It makes the code faster','It prevents memory leaks','Hardware only accepts volatile data','["A"]'::jsonb,'core_concept',60,'volatile tells the compiler to reload the value from memory every time, as the hardware might have updated it.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What is the advantage of using Bit-fields?','Space optimization for flags (status bits)','Higher precision for floats','Faster arithmetic','Automatic overflow checking','["A"]'::jsonb,'core_concept',60,'Bit-fields pack multiple Boolean or small numeric values into a single memory word.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','An ''Embedded C'' developer uses structs mostly for:','Object-oriented UI','Mapping Command/Status registers of peripherals','Browser development','SQL queries','["B"]'::jsonb,'core_concept',60,'Structs provide a structured way to access fixed hardware memory layouts.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','When a large struct is needed in a function, it is better to pass:','By value','By pointer (address)','Global copy','By copying to heap','["B"]'::jsonb,'core_concept',60,'Passing a pointer avoids the overhead of copying every byte of a large structure.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Bit-masking is an alternative to what C feature?','Pointers','UML Diagrams','Bit-fields','Recursion','["C"]'::jsonb,'core_concept',60,'One can use bitwise operators (masking) or bit-fields to manipulate specific bits.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Which operations are valid for structure variables?','Copying to another struct of same type','Passing to a function by value','Comparison with ''=='' operator','Retrieving address with &','["A","B","D"]'::jsonb,'multi_correct',60,'C does not allow direct comparison of structs with ''==''; you must compare members manually.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Identify properties of C unions:','Only one member is validly stored at a time','Total size is size of its largest member','Provides type punning (accessing raw bytes differently)','Members are placed at sequential addresses','["A","B","C"]'::jsonb,'multi_correct',60,'Union members start at the SAME address, sequentially is for structures.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Which keywords are used in creating complex user data types?','struct','union','enum','typedef','["A","B","C","D"]'::jsonb,'multi_correct',60,'structs, unions, enums, and typedef are the building blocks of C custom types.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','What can happen when mapping a struct to hardware registers?','Padding bytes might shift register positions','Endianness might flip multi-byte data','Hardware might not allow byte-access (alignment)','The struct name is uploaded to the device','["A","B","C"]'::jsonb,'multi_correct',60,'Careful control over alignment and endianness is vital; names are just for the code.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Which of these describe self-referential structures correctly?','Must use pointers to refer to itself','Basic unit of a Linked List','Can be nested infinitely by value','Used to describe tree hierarchies','["A","B","D"]'::jsonb,'multi_correct',60,'You cannot nest a struct inside itself by value (infinite size); you must use pointers.','pregenerated'),
('f796b963-69ee-428c-98f8-1bc9b1cf59b5','Ways to initialize a struct variable during declaration:','struct S s = { 10, 20 };','struct S s = { .a = 5 }; (Designated)','struct S s = s_other;','s = calloc(1, size);','["A","B","C"]'::jsonb,'multi_correct',60,'A, B, and C are declaration-time initializations. D is a runtime assignment.','pregenerated')
